// n8n: CODE - SB URLs after outreach mail
const j = $('CODE - Merge Gmail send response').first().json;
const mapped = $('CODE - SB map session id').first().json;
const b = String(j.config?.supabase_url || '').replace(/\/+$/, '');
const tb = j.config?.table_assessment_sessions || 'assessment_sessions';
const sessionId = mapped.session_db_id || mapped.id;
const threadId = String(j.gmail_thread_id || '').trim();
const isRealThread =
  threadId.length > 0 && !threadId.startsWith('pending-') && !threadId.startsWith('draft-');

return [
  {
    json: {
      ...j,
      ...mapped,
      gmail_thread_id: isRealThread ? threadId : mapped.gmail_thread_id,
      session_phase: j.session_phase || 1,
      _sb_insert_candidates: `${b}/rest/v1/${j.config?.table_candidates || 'candidates'}`,
      _gmail_patch_url:
        sessionId && isRealThread
          ? `${b}/rest/v1/${tb}?id=eq.${encodeURIComponent(String(sessionId))}`
          : '',
      _gmail_patch_body: isRealThread
        ? { gmail_thread_id: threadId, updated_at: new Date().toISOString() }
        : null,
    },
  },
];

