// n8n: CODE - SB prepare session insert
// Flow: GATE Shortlist → this node → HTTP insert → map session id → MAIL → Merge Gmail → PATCH thread (see n8n_code_patch_gmail_thread.js)

function timerBounds(config) {
  const min = Number(config?.timer_min_seconds);
  const max = Number(config?.timer_max_seconds);
  return {
    min: Number.isFinite(min) && min > 0 ? min : 60,
    max: Number.isFinite(max) && max > 0 ? max : 600,
  };
}

function useAiTimeLimitSeconds(raw, config) {
  const { min, max } = timerBounds(config);
  let sec = Number(raw);
  if (!Number.isFinite(sec) || sec <= 0) {
    sec = Number(config?.default_phase_seconds ?? config?.phase_1_timer_seconds ?? 240);
  }
  if (!Number.isFinite(sec) || sec <= 0) sec = 240;
  return Math.min(max, Math.max(min, Math.round(sec)));
}

function buildDeadline(isoStart, seconds) {
  const start = isoStart ? new Date(isoStart) : new Date();
  return new Date(start.getTime() + seconds * 1000).toISOString();
}

function uuidv4() {
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
    const r = (Math.random() * 16) | 0;
    const v = c === 'x' ? r : (r & 0x3) | 0x8;
    return v.toString(16);
  });
}

function isRealGmailThreadId(id) {
  const s = String(id || '').trim();
  return s.length > 0 && !s.startsWith('pending-') && !s.startsWith('draft-');
}

function pickGmailThreadId(...candidates) {
  for (const id of candidates) {
    if (isRealGmailThreadId(id)) return String(id).trim();
  }
  return '';
}

const parse = $('CODE - Parse CV screening outcome').first().json;
const inp = $input.first().json || {};
const httpOut =
  inp.candidate_email || inp.stage || inp.notes || inp.gmail_thread_id ? inp : {};

const notes =
  typeof httpOut?.notes === 'object' && httpOut.notes ? httpOut.notes : parse.screening || {};

const cfg =
  parse.config || $('CFG - Workflow configuration').first().json.config || {};

const jdTitle = String(cfg.requisition_title || '').trim();
const jdReq = String(cfg.requisition_requirements || '').trim();
if (!jdTitle || !jdReq) {
  throw new Error(
    'JD missing in config — recruiter form (requisition_title + requisition_requirements) must run before session insert.'
  );
}

const nowIso = new Date().toISOString();
const candidate_email = String(
  httpOut.candidate_email || parse.candidate_email || inp.candidate_email || ''
).trim().toLowerCase();

const qText = String(
  parse.phase_1_question || notes.phase_1_question || ''
).trim();

const aiSeconds =
  parse.phase_1_time_limit_seconds ??
  notes.time_limit_seconds ??
  notes.timeLimitSeconds;

const time_limit_seconds = useAiTimeLimitSeconds(aiSeconds, cfg);
const deadline_at = buildDeadline(nowIso, time_limit_seconds);
const complexity_tier =
  parse.phase_1_complexity_tier || notes.complexity_tier || notes.complexityTier || null;

const cv = String(parse.cv_plaintext || parse.cv_text || '').slice(0, 12000);

const session_uuid = uuidv4();
const realThread = pickGmailThreadId(
  parse.gmail_thread_id,
  httpOut.gmail_thread_id,
  inp.gmail_thread_id
);
// Temporary until MAIL + PATCH; never use pending-email@...
const gmail_thread_id = realThread || `draft-${session_uuid}`;

const requisition_id =
  String(parse.requisition_id || httpOut.requisition_id || inp.requisition_id || '').trim() ||
  jdTitle
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 64);

const sessionBody = {
  id: session_uuid,
  gmail_thread_id,
  candidate_email,
  current_phase: 1,
  max_phases: cfg.max_questions ?? 5,
  status: 'assessment',
  screening: parse.screening || notes,
  score: httpOut.score ?? parse.score ?? null,
  requisition_id,
  fingerprint: httpOut.fingerprint || parse.fingerprint || inp.fingerprint || '',
  cv_plaintext: cv,
  last_question_sent_at: nowIso,
  updated_at: nowIso,
  config: {
    requisition_title: jdTitle,
    requisition_requirements: jdReq,
    organization_name: cfg.organization_name,
    groq_model: cfg.groq_model,
    gemini_model: cfg.gemini_model,
    max_questions: cfg.max_questions,
    interviewer_email: cfg.interviewer_email,
    supabase_url: cfg.supabase_url,
    supabase_key: cfg.supabase_key,
    table_assessment_sessions: cfg.table_assessment_sessions,
    fail_score_threshold: cfg.fail_score_threshold ?? 30,
    pass_score_threshold: cfg.pass_score_threshold ?? 60,
    timer_min_seconds: cfg.timer_min_seconds ?? 60,
    timer_max_seconds: cfg.timer_max_seconds ?? 600,
  },
  interview_history: [
    {
      phase: 1,
      question_text: qText,
      answer_text: null,
      score: null,
      suggested_answer: null,
      feedback: null,
      time_limit_seconds,
      deadline_at,
      complexity_tier,
      sent_at: nowIso,
    },
  ],
};

const b = String(cfg.supabase_url || '').replace(/\/+$/, '');
const tb = cfg.table_assessment_sessions || 'assessment_sessions';

return [
  {
    json: {
      ...parse,
      ...httpOut,
      config: cfg,
      candidate_email,
      gmail_thread_id,
      gmail_thread_is_pending: !realThread,
      phase_1_question: qText,
      phase_1_time_limit_seconds: time_limit_seconds,
      requisition_id,
      _sb_insert_sessions: `${b}/rest/v1/${tb}`,
      _session_body: sessionBody,
      _now: nowIso,
      _q_text: qText,
    },
  },
];

function getWebhookPayload() {
  const tries = [
    () => $('TRG - Webhook CV ingest').first().json,
    () => $('MUX - Combine manual and webhook').first().json,
    () => $('TRG - Manual (testing)').first().json,
  ];
  for (const fn of tries) {
    try {
      const raw = fn();
      const body = raw.body || raw;
      if (
        body?.requisition_title ||
        body?.requisition_requirements ||
        body?.candidate_email ||
        body?.cv_text
      ) {
        return body;
      }
    } catch (e) {
      /* next */
    }
  }
  return {};
}

function pick(body, ...keys) {
  for (const k of keys) {
    const v = body[k];
    if (v != null && String(v).trim()) return String(v).trim();
  }
  return '';
}

const pdf = $input.first().json;
const body = getWebhookPayload();

const requisition_title = pick(body, 'requisition_title', 'job_title');
const requisition_requirements = pick(
  body,
  'requisition_requirements',
  'jd_text',
  'job_requirements'
);
const candidate_email = pick(body, 'candidate_email', 'email').toLowerCase();
const cv_text = String(pdf.text || pick(body, 'cv_text') || '').trim();
const requisition_id = pick(body, 'requisition_id');

if (!requisition_title) {
  throw new Error(
    'Missing requisition_title — recruiter form must send job title (requisition_title).'
  );
}
if (!requisition_requirements) {
  throw new Error(
    'Missing requisition_requirements — recruiter form must send JD text.'
  );
}
if (!candidate_email) {
  throw new Error('Missing candidate_email from recruiter form.');
}
if (!cv_text) {
  throw new Error('Missing CV — upload PDF (cv_file) or paste cv_text.');
}

return [
  {
    json: {
      requisition_title,
      requisition_requirements,
      candidate_email,
      cv_text,
      requisition_id,
      jd_source: 'frontend_form',
    },
  },
];

const base = $('CODE - SB prepare session insert').first().json;
let row = $input.first().json;
if (Array.isArray(row)) row = row[0];
const session_id = row?.id;
if (!session_id) {
  throw new Error('Supabase did not return assessment session id — check HTTP - SB insert assessment session');
}
return [{
  json: {
    ...base,
    session_db_id: session_id,
    id: session_id,
  },
}];
